oxy_webhelp_navlinks = {"migration_arch_loc_rcv-d27248e7912":{"topics":[{"title":"Prerequisites for migrating archival locations to RCV","shortdesc":"<p class=\"shortdesc\">Before migrating your data center archival location to Rubrik Cloud Vault, ensure         your source location, Rubrik cluster, and SLA Domain configurations meet all         requirements.<\/p>","href":"saas\/rcv_prereq_arch_loc_migration.html","attributes":{"data-id":"rcv_prereq_arch_loc_migration"},"menu":{"hasChildren":false},"tocID":"rcv_prereq_arch_loc_migration-d27248e7923","topics":[]},{"title":"RCV migration workflow","shortdesc":"<p class=\"shortdesc\">Migration of archival locations to Rubrik Cloud Vault involves specific         responsibilities for both the customer and Rubrik Professional Services, depending on         whether the workflow is customer-hosted or Rubrik-hosted.<\/p>","href":"saas\/rcv_migration_workflow.html","attributes":{"data-id":"rcv_migration_workflow"},"menu":{"hasChildren":false},"tocID":"rcv_migration_workflow-d27248e7934","topics":[]},{"title":"Customer-hosted migration process","shortdesc":"<p class=\"shortdesc\">You can migrate an archival location to RCV by running the migration tool in your own         AWS environment.<\/p>","href":"saas\/rcv_cust_managed_migration_process.html","attributes":{"data-id":"rcv_cust_managed_migration_process"},"menu":{"hasChildren":false},"tocID":"rcv_cust_managed_migration_process-d27248e7945","next":"rcv_cust_managed_migration_process-d27248e7945"},{"title":"Rubrik-hosted migration process","shortdesc":"<p class=\"shortdesc\">You can migrate an archival location to RCV by authorizing Rubrik to run the         migration tool within the Rubrik AWS environment.<\/p>","href":"saas\/rcv_rbk_managed_migration_process.html","attributes":{"data-id":"rcv_rbk_managed_migration_process"},"menu":{"hasChildren":false},"tocID":"rcv_rbk_managed_migration_process-d27248e8003","next":"rcv_rbk_managed_migration_process-d27248e8003"}]}};